ERC20_ABI = [
    {"constant": True, "inputs": [{"name": "_owner", "type": "address"}], "name": "balanceOf", "outputs": [{"name": "balance", "type": "uint256"}], "type": "function"},
    {"constant": False, "inputs": [{"name": "_spender", "type": "address"}, {"name": "_value", "type": "uint256"}], "name": "approve", "outputs": [{"name": "success", "type": "bool"}], "type": "function"}
]

# --- 2. THE INFRASTRUCTURE ---
def get_hydra_w3():
    endpoints = [os.getenv("RPC_URL"), "https://polygon-rpc.com", "https://1rpc.io/matic"]
    for url in endpoints:
        if not url: continue
        try:
            _w3 = Web3(Web3.HTTPProvider(url.strip(), request_kwargs={'timeout': 10}))
            if _w3.is_connected():
                _w3.middleware_onion.inject(ExtraDataToPOAMiddleware, layer=0)
                return _w3
        except: continue
    return None

w3 = get_hydra_w3()
if not w3: exit("FATAL: RPC Failure.")

usdc_e_contract = w3.eth.contract(address=USDC_E, abi=ERC20_ABI)

def get_vault():
    seed = os.getenv("WALLET_SEED", "").strip()
    Account.enable_unaudited_hdwallet_features()
    try:
        # Accepts either Mnemonic Phrase or Private Key Hex
        return Account.from_mnemonic(seed) if " " in seed else Account.from_key(seed)
    except: return None

vault = get_vault()
if not vault: exit("FATAL: Vault Key Invalid.")

def init_clob():
    """Initializes the Polymarket CLOB Client with correct EOA Signature Type."""
    try:
        # KEY FIX: Standard Private Keys must use signature_type=0
        sig_type = int(os.getenv("SIGNATURE_TYPE", 0)) 
        
        client = ClobClient(
            host="https://clob.polymarket.com", 
            key=vault.key.hex(), 
            chain_id=137, 
            signature_type=sig_type, 
            funder=vault.address
        )
        # Ensure API credentials are fresh and matched to the wallet
        client.set_api_creds(client.create_or_derive_api_creds())
        return client
    except Exception as e:
        print(f"CLOB INIT ERROR: {e}")
        return None

clob_client = init_clob()

# --- 3. LOGIC & ARBITRAGE CORE ---
async def get_safe_price(token_id):
    """Walks the book to find a realistic fill price."""
    try:
        url = f"https://clob.polymarket.com/book?token_id={token_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        data = r.json()
        if data.get('asks'):
            # Use price from slightly deeper in the book to avoid 'invalid signature' timing errors
            depth = min(len(data['asks']) - 1, 1)
            deep_price = float(data['asks'][depth]['price'])
            return min(0.99, round(deep_price + 0.005, 3))
    except: pass
    return 0.99

def calculate_arbitrage_guaranteed(p_yes, p_no, total_capital):
    combined_prob = p_yes + p_no
    if combined_prob >= 1.0 or combined_prob <= 0: return None
    stake_yes = np.floor(((p_no / combined_prob) * total_capital) * 100) / 100
    stake_no = np.floor(((p_yes / combined_prob) * total_capital) * 100) / 100
    roi = round(((1 / combined_prob) - 1) * 100, 2)
    return {"stake_yes": stake_yes, "stake_no": stake_no, "roi": roi}

async def fetch_full_market(cond_id):
    try:
        url = f"https://clob.polymarket.com/markets/{cond_id}"
        r = await asyncio.to_thread(requests.get, url, timeout=5)
        d = r.json()
        return {t['outcome'].upper(): {"id": t['token_id'], "price": float(t['price'])} for t in d.get('tokens', [])}
    except: return None

async def scour_arbitrage():
    global ARBI_CACHE
    ARBI_CACHE = []
    # Targeted Tag IDs: Politics, Crypto, Sports, etc.
    tags = [1, 10, 100, 4, 6]
    for tag in tags:
        url = f"https://gamma-api.polymarket.com/events?active=true&closed=false&limit=15&tag_id={tag}"
        try:
            resp = await asyncio.to_thread(requests.get, url, timeout=5)
            for e in resp.json():
                m = e.get('markets', [])
                if not m: continue
                m_data = await fetch_full_market(m[0]['conditionId'])
                if m_data and 'YES' in m_data and 'NO' in m_data:
                    arb = calculate_arbitrage_guaranteed(m_data['YES']['price'], m_data['NO']['price'], 100.0)
                    if arb and arb['roi'] > 0.5: # Only show ROI > 0.5%
                        ARBI_CACHE.append({
                            "title": e.get('title')[:30], 
                            "yes_id": m_data['YES']['id'], 
                            "no_id": m_data['NO']['id'], 
                            "p_y": m_data['YES']['price'], 
                            "p_n": m_data['NO']['price'], 
                            "roi": arb['roi']
                        })
        except: continue
    return len(ARBI_CACHE) > 0

# --- 4. TELEGRAM HANDLERS ---
async def start(update, context):
    btns = [['🚀 START ARBI-SCAN'], ['💳 VAULT', '🔧 FIX APPROVAL']]
    await update.message.reply_text(f"{LOGO}\n<b>HYDRA PROTOCOL READY.</b>", 
                                  reply_markup=ReplyKeyboardMarkup(btns, resize_keyboard=True), 
                                  parse_mode='HTML')

async def main_handler(update, context):
    cmd = update.message.text
    if 'START ARBI-SCAN' in cmd:
        m = await update.message.reply_text("📡 <b>SCANNING POLYMARKET...</b>", parse_mode='HTML')
        if await scour_arbitrage():
            kb = [[InlineKeyboardButton(f"🎯 {a['title']} ({a['roi']}%)", callback_data=f"ARB_{i}")] for i, a in enumerate(ARBI_CACHE[:8])]
            await m.edit_text("<b>OPPORTUNITIES FOUND:</b>", reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')
        else: await m.edit_text("🛰 <b>NO DISCREPANCIES DETECTED.</b>")
    
    elif 'FIX APPROVAL' in cmd:
        try:
            tx = usdc_e_contract.functions.approve(CTF_EXCHANGE, 2**256 - 1).build_transaction({
                'from': vault.address,
                'nonce': w3.eth.get_transaction_count(vault.address),
                'gasPrice': int(w3.eth.gas_price * 1.2)
            })
            signed_tx = w3.eth.account.sign_transaction(tx, vault.key)
            tx_hash = w3.eth.send_raw_transaction(signed_tx.rawTransaction)
            await update.message.reply_text(f"✅ <b>Approval Sent:</b> {tx_hash.hex()}", parse_mode='HTML')
        except Exception as e:
            await update.message.reply_text(f"❌ <b>Approval Failed:</b> {str(e)}")

    elif 'VAULT' in cmd:
        bal = usdc_e_contract.functions.balanceOf(vault.address).call()
        await update.message.reply_text(f"<b>VAULT STATUS</b>\n<code>{vault.address}</code>\n<b>USDC.e:</b> ${bal/1e6:.2f}", parse_mode='HTML')

async def handle_query(update, context):
    q = update.callback_query; await q.answer()
    stake = 10.0 # Default trade size
    
    if "ARB_" in q.data:
        idx = int(q.data.split("_")[1])
        target = ARBI_CACHE[idx]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        msg = f"<b>{target['title']}</b>\n✅ YES Stake: ${calc['stake_yes']}\n❌ NO Stake: ${calc['stake_no']}\n💰 Expected ROI: {calc['roi']}%"
        kb = [[InlineKeyboardButton("🔥 EXECUTE DUAL STRIKE", callback_data=f"EXE_{idx}")]]
        await q.edit_message_text(msg, reply_markup=InlineKeyboardMarkup(kb), parse_mode='HTML')
    
    elif "EXE_" in q.data:
        idx = int(q.data.split("_")[1])
        target = ARBI_CACHE[idx]
        calc = calculate_arbitrage_guaranteed(target['p_y'], target['p_n'], stake)
        
        results = []
        for (t_id, amt) in [(target['yes_id'], calc['stake_yes']), (target['no_id'], calc['stake_no'])]:
            try:
                # Build Market Order Argument
                order_args = MarketOrderArgs(
                    token_id=str(t_id),
                    amount=float(amt),
                    side=BUY
                )
                
                # KEY FIX: Standard Market Order signing
                signed_order = clob_client.create_market_order(order_args)
                resp = clob_client.post_order(signed_order)
                
                if resp.get("success") or "order_id" in resp:
                    results.append(True)
                else:
                    results.append(False)
            except Exception as e:
                print(f"Trade Error: {e}")
                results.append(False)
        
        status = "✅ <b>STRIKE COMPLETE</b>" if all(results) else "⚠️ <b>PARTIAL FILL / REVERT</b>"
        await context.bot.send_message(q.message.chat_id, status, parse_mode='HTML')

# --- 5. EXECUTION ---
if __name__ == "__main__":
    bot_token = os.getenv("TELEGRAM_BOT_TOKEN")
    if not bot_token: exit("FATAL: Missing Telegram Token.")
    
    app = ApplicationBuilder().token(bot_token).build()
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CallbackQueryHandler(handle_query))
    app.add_handler(MessageHandler(filters.TEXT & (~filters.COMMAND), main_handler))
    
